import{_ as a,o as n,c as e,a3 as s}from"./chunks/framework.BlfGB29P.js";const u=JSON.parse('{"title":"框架概述","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/overview.md","filePath":"cosmos/framework/overview.md","lastUpdated":1783773945000}'),d={name:"cosmos/framework/overview.md"};function o(r,t,i,l,p,c){return n(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="框架概述" tabindex="-1">框架概述 <a class="header-anchor" href="#框架概述" aria-label="Permalink to &quot;框架概述&quot;">​</a></h1><p>XiHan.Framework 是面向企业级应用的<strong>模块化后端框架</strong>，专为前后端分离的 ASP.NET Core 应用设计。它把一套完整的后端能力拆成许多职责单一的模块，通过 <code>[DependsOn]</code> 属性声明依赖、自动拓扑排序加载，并以<strong>应用服务 + 动态 API</strong> 约定统一对外暴露接口。</p><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ul><li><strong>分层架构</strong> —— 遵循清晰的分层，避免循环依赖</li><li><strong>依赖倒置</strong> —— 高层模块不依赖低层模块，二者都依赖抽象接口</li><li><strong>单一职责</strong> —— 每个包只负责一个特定的功能领域</li><li><strong>开闭原则</strong> —— 对扩展开放、对修改关闭，通过接口和抽象类支持自定义</li><li><strong>优先 .NET 10</strong> —— 使用内置能力（DI、日志、序列化），仅在必要时引入第三方库</li><li><strong>性能优化</strong> —— 利用 .NET 10 高性能特性，目标支持 AOT 编译</li></ul><h2 id="为什么是-模块化" tabindex="-1">为什么是&quot;模块化&quot; <a class="header-anchor" href="#为什么是-模块化" aria-label="Permalink to &quot;为什么是&quot;模块化&quot;&quot;">​</a></h2><p>传统项目里，<code>Program.cs</code> 常常堆满几十行 <code>builder.Services.AddXxx()</code>，顺序、依赖、初始化时机全靠人肉维护。XiHan.Framework 把每一块能力封装成一个<strong>模块类</strong>，模块自己负责：</p><ul><li>注册自己需要的服务（<code>ConfigureServices</code>）</li><li>声明自己依赖谁（<code>[DependsOn]</code>）</li><li>在合适的生命周期节点接入中间件、后台任务等（<code>OnApplicationInitialization</code> 等）</li></ul><p>你只需要在自己的应用模块上声明&quot;我要用哪些模块&quot;，框架会<strong>自动把整棵依赖树按正确顺序装配好</strong>。新增或移除一块能力，就是加/减一行 <code>[DependsOn]</code>。</p><blockquote><p>想深入这套机制，见 <a href="./concepts/modularity">核心概念 · 模块系统</a> 与 <a href="./concepts/lifecycle">生命周期</a>。</p></blockquote><h2 id="分层架构" tabindex="-1">分层架构 <a class="header-anchor" href="#分层架构" aria-label="Permalink to &quot;分层架构&quot;">​</a></h2><p>框架采用严格的模块化分层，通过 <code>[DependsOn]</code> 强制依赖关系，自动拓扑排序加载：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                         7. Web 层                                │</span></span>
<span class="line"><span>│  Web.Docs → Web.Api → Web.Core    Web.Gateway    Web.RealTime    │</span></span>
<span class="line"><span>│                                    Web.Grpc                       │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                       6. 基础设施层                              │</span></span>
<span class="line"><span>│  Data  Authentication  Authorization  Caching  EventBus          │</span></span>
<span class="line"><span>│  AI  Bot  Tasks  Traffic  Upgrade  Messaging  ObjectStorage      │</span></span>
<span class="line"><span>│  Logging  Observability  SearchEngines  Script  Http  Castle …   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        5. 应用层                                 │</span></span>
<span class="line"><span>│  Application → Application.Contracts                              │</span></span>
<span class="line"><span>│  MultiTenancy → MultiTenancy.Abstractions                        │</span></span>
<span class="line"><span>│  Validation → Validation.Abstractions      Settings              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        4. 领域层                                 │</span></span>
<span class="line"><span>│  Domain → Domain.Shared                                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                        3. 核心层                                 │</span></span>
<span class="line"><span>│  Core（模块系统 / DI / 生命周期 / 选项模式 / 异常处理）          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                      2. 元数据层                                 │</span></span>
<span class="line"><span>│  Metadata（框架信息 / 版本 / 平台）                              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                      1. 公共层                                   │</span></span>
<span class="line"><span>│  Utils（零依赖通用工具库）                                       │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>分层规则</strong>：任何模块只能依赖比它更低的层，绝不反向。这保证了依赖图无环、可裁剪、可测试。</p><h2 id="命名约定" tabindex="-1">命名约定 <a class="header-anchor" href="#命名约定" aria-label="Permalink to &quot;命名约定&quot;">​</a></h2><ul><li><code>XiHan.Framework.[模块名]</code> —— 通用类库，使用 <code>Microsoft.NET.Sdk</code></li><li><code>XiHan.Framework.Web.[模块名]</code> —— Web 相关功能，使用 <code>Microsoft.NET.Sdk.Web</code></li><li>每个模块的入口类名为 <code>XiHan[模块名]Module</code>，继承 <code>XiHanModule</code></li><li>纯工具库（<code>Utils</code> / <code>Metadata</code>）与分析器（<code>Analyzers</code>）没有模块类，直接引用即可</li></ul><h2 id="核心机制速览" tabindex="-1">核心机制速览 <a class="header-anchor" href="#核心机制速览" aria-label="Permalink to &quot;核心机制速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机制</th><th>说明</th><th>深入</th></tr></thead><tbody><tr><td>模块系统</td><td><code>XiHanModule</code> + <code>[DependsOn]</code>，自动拓扑排序加载</td><td><a href="./concepts/modularity">模块系统</a></td></tr><tr><td>生命周期</td><td>服务注册 3 钩子 + 应用初始化 3 钩子 + 关机 1 钩子</td><td><a href="./concepts/lifecycle">生命周期</a></td></tr><tr><td>依赖注入</td><td>约定式注册（<code>ITransientDependency</code> 等）+ 选项模式</td><td><a href="./concepts/dependency-injection">依赖注入</a></td></tr><tr><td>动态 API</td><td>应用服务无需写 Controller，自动暴露为 REST 接口</td><td><a href="./concepts/dynamic-api">动态 API</a></td></tr></tbody></table><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>技术</th><th>版本</th></tr></thead><tbody><tr><td>运行时</td><td>.NET</td><td>10.0</td></tr><tr><td>语言</td><td>C#</td><td>Latest</td></tr><tr><td>ORM</td><td>SqlSugar</td><td>5.1.4.216</td></tr><tr><td>日志</td><td>Serilog</td><td>10.0.0</td></tr><tr><td>缓存</td><td>HybridCache + StackExchange.Redis</td><td>10.7.0 / 10.0.9</td></tr><tr><td>AOP</td><td>Castle DynamicProxy</td><td>5.2.1</td></tr><tr><td>加密</td><td>BouncyCastle</td><td>2.6.2</td></tr><tr><td>序列化</td><td>System.Text.Json + Newtonsoft.Json</td><td>13.0.4</td></tr><tr><td>模板引擎</td><td>Scriban</td><td>7.2.5</td></tr><tr><td>AI</td><td>Microsoft.Extensions.AI + Microsoft.Agents.AI + MCP</td><td>10.7.0 / 1.13.0 / 1.4.1</td></tr><tr><td>HTTP 韧性</td><td>Polly</td><td>10.0.9</td></tr><tr><td>gRPC</td><td>Grpc.AspNetCore</td><td>2.80.0</td></tr><tr><td>实时通信</td><td>ASP.NET Core SignalR</td><td>-</td></tr><tr><td>API 文档</td><td>Scalar + Swashbuckle</td><td>2.16.11 / 10.2.3</td></tr><tr><td>IP 定位</td><td>ip2region</td><td>3.0.2</td></tr><tr><td>消息通知</td><td>MailKit + Telegram.Bot</td><td>4.17.0 / 22.10.1.1</td></tr></tbody></table><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>依赖</th><th>版本</th></tr></thead><tbody><tr><td>.NET SDK</td><td>10.0+</td></tr><tr><td>C#</td><td>Latest</td></tr><tr><td>支持平台</td><td>Windows / Linux / macOS</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./quickstart">快速上手</a>：动手建第一个 Web API</li><li><a href="./concepts/modularity">核心概念</a>：理解框架的运转方式</li><li><a href="./packages/">模块总览</a>：查阅你要用的每一个包</li></ul>`,23)])])}const b=a(d,[["render",o]]);export{u as __pageData,b as default};
